sed -i 's/ir.Stmt.AssignmentStmtSoot tassign = new ir.Stmt.AssignmentStmtSoot(tempLocal, /* IExpr *\/(IExpr) e.clone(),/IExpr cloned = (IExpr) e.clone();\\\n                if (cloned instanceof BinOp) {\\\n                    BinOp b = (BinOp) cloned;\\\n                    b.setLeft(rewriteExpr(b.getLeft(), available, tempMap, u, tempCounter, units));\\\n                    b.setRight(rewriteExpr(b.getRight(), available, tempMap, u, tempCounter, units));\\\n                } else if (cloned instanceof Call) {\\\n                    Call c = (Call) cloned;\\\n                    c.setFunc(rewriteExpr(c.getFunc(), available, tempMap, u, tempCounter, units));\\\n                    List<IExpr> newArgs = new ArrayList<>();\\\n                    for (IExpr a : c.getArgs())\\\n                        newArgs.add(rewriteExpr(a, available, tempMap, u, tempCounter, units));\\\n                    c.setArgs(newArgs);\\\n                } else if (cloned instanceof Attribute) {\\\n                    Attribute a = (Attribute) cloned;\\\n                    a.setValue(rewriteExpr(a.getValue(), available, tempMap, u, tempCounter, units));\\\n                } else if (cloned instanceof Subscript) {\\\n                    Subscript s = (Subscript) cloned;\\\n                    s.setValue(rewriteExpr(s.getValue(), available, tempMap, u, tempCounter, units));\\\n                }\\\n\\\n                ir.Stmt.AssignStmt irAssign = new ir.Stmt.AssignStmt();\\\n                irAssign.setTargets(new ArrayList<>(java.util.Arrays.asList(tempLocal)));\\\n                irAssign.setRHS(cloned);\\\n\\\n                ir.Stmt.AssignmentStmtSoot tassign = new ir.Stmt.AssignmentStmtSoot(tempLocal, cloned, irAssign);/' src/analysis/AvailableExpression/AvailableExpressionAnalysis.java

